// ── Road shield generator ─────────────────────────────────────────────────────
// Draws a real road sign on an offscreen canvas and returns ImageData.
// Called lazily via map.on('styleimagemissing', ...) — only generates each
// unique ref once, then caches it.

const SHIELD_COLORS = {
  motorway: { bg: '#cc1111' },
  trunk: { bg: '#3a81fc' },
  primary: { bg: '#3a81fc' },
  secondary: { bg: '#3a81fc' },
  local: { bg: '#b89060' },
  euro: { bg: '#2e7d32' },
  construction: { bg: '#888888' },
};

// Road ref → E-route lookup (static mapping from official sources)
// When drawing a road shield, if the ref has an E-route, draw it stacked below
// This is mutable so admin overrides can be applied at runtime.
let EURO_ROUTES = {
  // ── Czech motorways — source: OSM int_ref field, way-count weighted ─────────
  'D0': ['E50'],            // Prague ring (also E48,E55,E65 — E50 dominant)
  'MO': ['E50'],            // same road different ref
  'D1': ['E50', 'E65'],      // Praha–Brno (E50 dominant), Brno–SK (E65)
  'D2': ['E65'],            // Brno–Bratislava
  'D3': ['E55'],            // Praha–C.Budějovice
  'D5': ['E50'],            // Praha–Plzeň–Rozvadov
  'D6': ['E48', 'E49'],      // Praha–KV–Cheb (E48 dominant, E49 on border section)
  'D8': ['E55'],            // Praha–Ústí–Dresden
  'D10': ['E65'],            // Praha–Ml.Boleslav
  'D11': ['E67'],            // Praha–Hradec Králové
  'D35': ['E442'],           // Olomouc–Lipník
  'D46': ['E462'],           // Vyškov–Olomouc
  'D48': ['E462'],           // Bělotín–Frýdek-Místek
  'D52': ['E461'],           // Brno–Pohořelice (new)
  // Czech expressways
  'R1': ['E571', 'E58'],     // Slovak R1
  'R2': ['E571', 'E58'],     // Slovak R2
  'R4': ['E58'],
  // Czech primary roads
  '6': ['E48'],
  '10': ['E65'],
  '11': ['E75'],            // Ostrava–Mosty u Jablunkova
  '17': ['E442'],
  '20': ['E49'],
  '21': ['E49'],
  '27': ['E53'],
  '33': ['E67'],
  '35': ['E442'],
  '50': ['E50'],
  '63': ['E442'],           // Teplice–Děčín
  // German Autobahns
  'A 3': ['E56'],
  'A 6': ['E50'],
  'A 9': ['E51'],
  'A 17': ['E55'],
  'A 70': ['E48'],
  'A 72': ['E441'],
  'A 92': ['E53'],
  // Austrian/Polish/Slovak
  'A1': ['E75'],
  'A2': ['E59'],
  'A4': ['E40'],
  'A8': ['E56'],
  'A9': ['E59'],
  'A10': ['E55'],
};

// Detect if a ref is a local road (5+ digits = district/local road)
function getShieldClass(roadClass, ref) {
  // 4+ digit numbers, optionally ending with a single letter (2341, 18512, 18052e, 17502a) = local district roads → brown
  if (ref && ref.length >= 4 && /^\d+[a-zA-Z]?$/.test(ref)) return 'local';
  return roadClass;
}

function drawRoadShield(ref, roadClass) {
  const effectiveClass = getShieldClass(roadClass, ref);
  const colors = SHIELD_COLORS[effectiveClass] || SHIELD_COLORS.primary;
  const FONT_SIZE = 9;
  const PADDING_X = 4;
  const PADDING_Y = 2;
  const BORDER = 1.5;  // outer border width
  const INNER_GAP = 1.5;  // gap between outer border and inner white line
  const RADIUS = 3;
  const SCALE = 1;    // no retina scaling — keeps size reasonable

  // Measure text
  const canvas0 = document.createElement('canvas');
  const ctx0 = canvas0.getContext('2d');
  ctx0.font = `bold ${FONT_SIZE}px Arial, sans-serif`;
  const tw = ctx0.measureText(ref).width;

  const W = Math.ceil(tw + PADDING_X * 2 + (BORDER + INNER_GAP) * 2);
  const H = FONT_SIZE + PADDING_Y * 2 + (BORDER + INNER_GAP) * 2;

  const canvas = document.createElement('canvas');
  canvas.width = W * SCALE;
  canvas.height = H * SCALE;
  const ctx = canvas.getContext('2d');
  ctx.scale(SCALE, SCALE);

  function roundRect(x, y, w, h, r) {
    ctx.beginPath();
    ctx.moveTo(x + r, y);
    ctx.lineTo(x + w - r, y);
    ctx.arcTo(x + w, y, x + w, y + r, r);
    ctx.lineTo(x + w, y + h - r);
    ctx.arcTo(x + w, y + h, x + w - r, y + h, r);
    ctx.lineTo(x + r, y + h);
    ctx.arcTo(x, y + h, x, y + h - r, r);
    ctx.lineTo(x, y + r);
    ctx.arcTo(x, y, x + r, y, r);
    ctx.closePath();
  }

  // 1. Outer colored border
  ctx.fillStyle = colors.bg;
  roundRect(0, 0, W, H, RADIUS);
  ctx.fill();

  // 2. White inner border line
  ctx.fillStyle = '#ffffff';
  roundRect(BORDER, BORDER, W - BORDER * 2, H - BORDER * 2, RADIUS - 1);
  ctx.fill();

  // 3. Colored fill inside white border
  ctx.fillStyle = colors.bg;
  roundRect(BORDER + INNER_GAP, BORDER + INNER_GAP,
    W - (BORDER + INNER_GAP) * 2, H - (BORDER + INNER_GAP) * 2, RADIUS - 2);
  ctx.fill();

  // 4. White bold text centered
  ctx.fillStyle = '#ffffff';
  ctx.font = `bold ${FONT_SIZE}px Arial, sans-serif`;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillText(ref, W / 2, H / 2);

  // 5. If this road has E-routes, draw a green shield stacked below
  const euroRefs = EURO_ROUTES[ref];
  if (euroRefs && euroRefs.length > 0) {
    const euroText = euroRefs[0];
    const EFS = FONT_SIZE;      // same font size as main shield
    const EPX = PADDING_X;
    const EPY = PADDING_Y;
    const EB = BORDER;
    const EIG = INNER_GAP;
    const ER = RADIUS;
    const GAP = 2;

    // Measure euro text properly
    const mCtx = document.createElement('canvas').getContext('2d');
    mCtx.font = `bold ${EFS}px Arial, sans-serif`;
    const ETW = mCtx.measureText(euroText).width;
    const EW = Math.ceil(ETW + EPX * 2 + (EB + EIG) * 2);
    const EH = Math.ceil(EFS + EPY * 2 + (EB + EIG) * 2);

    // Combined canvas — wide enough for both shields
    const CW = Math.max(W, EW);
    const CH = H + GAP + EH;
    const c2 = document.createElement('canvas');
    c2.width = CW * SCALE;
    c2.height = CH * SCALE;
    const ctx2 = c2.getContext('2d');
    ctx2.scale(SCALE, SCALE);

    // Center & paste main shield
    const mainX = (CW - W) / 2;
    ctx2.drawImage(canvas, 0, 0, W * SCALE, H * SCALE, mainX, 0, W, H);

    // Draw euro shield centered below
    const EX = (CW - EW) / 2;
    const EY = H + GAP;

    function rr2(x, y, w, h, r) {
      ctx2.beginPath();
      ctx2.moveTo(x + r, y); ctx2.lineTo(x + w - r, y);
      ctx2.arcTo(x + w, y, x + w, y + r, r); ctx2.lineTo(x + w, y + h - r);
      ctx2.arcTo(x + w, y + h, x + w - r, y + h, r); ctx2.lineTo(x + r, y + h);
      ctx2.arcTo(x, y + h, x, y + h - r, r); ctx2.lineTo(x, y + r);
      ctx2.arcTo(x, y, x + r, y, r); ctx2.closePath();
    }
    ctx2.fillStyle = '#2e7d32'; rr2(EX, EY, EW, EH, ER); ctx2.fill();
    ctx2.fillStyle = '#ffffff'; rr2(EX + EB, EY + EB, EW - EB * 2, EH - EB * 2, ER - 1); ctx2.fill();
    ctx2.fillStyle = '#2e7d32'; rr2(EX + EB + EIG, EY + EB + EIG, EW - (EB + EIG) * 2, EH - (EB + EIG) * 2, ER - 2); ctx2.fill();
    ctx2.fillStyle = '#ffffff';
    ctx2.font = `bold ${EFS}px Arial, sans-serif`;
    ctx2.textAlign = 'center';
    ctx2.textBaseline = 'middle';
    ctx2.fillText(euroText, CW / 2, EY + EH / 2);

    return { data: ctx2.getImageData(0, 0, CW * SCALE, CH * SCALE).data, width: CW * SCALE, height: CH * SCALE };
  }

  return { data: ctx.getImageData(0, 0, W * SCALE, H * SCALE).data, width: W * SCALE, height: H * SCALE };
}

function addShieldImage(map, imageId) {
  try {
    // Parse "shield-{class}-{shield_text}" e.g. "shield-motorway-D1", "shield-trunk-MO"
    const withoutPrefix = imageId.slice('shield-'.length);
    const classEnd = withoutPrefix.indexOf('-');
    if (classEnd < 0) return;
    const roadClass = withoutPrefix.slice(0, classEnd);
    const shieldText = withoutPrefix.slice(classEnd + 1);
    if (!shieldText || shieldText === 'undefined') return;

    const { data, width, height } = drawRoadShield(shieldText, roadClass);
    map.addImage(imageId, { width, height, data });
  } catch (e) {
    // Silently skip
  }
}


